import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate, useLocation } from 'react-router-dom';
import './AppointmentForm.css';

const AppointmentForm = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const searchParams = new URLSearchParams(location.search);
  const doctorId = searchParams.get('doctor');

  const [formData, setFormData] = useState({
    patientName: '',
    patientEmail: '',
    patientPhone: '',
    age: '',
    gender: '',
    appointmentDate: '',
    appointmentTime: '',
    symptoms: '',
    notes: ''
  });

  const [doctor, setDoctor] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [availableTimeSlots, setAvailableTimeSlots] = useState([]);
  const [submitStatus, setSubmitStatus] = useState({ loading: false, error: null });

  useEffect(() => {
    if (doctorId) {
      fetchDoctorDetails();
    }
  }, [doctorId]);

  useEffect(() => {
    if (formData.appointmentDate && doctor) {
      const dayOfWeek = new Date(formData.appointmentDate).toLocaleDateString('en-US', { weekday: 'long' });
      if (doctor.availableDays.includes(dayOfWeek)) {
        setAvailableTimeSlots(doctor.timeSlots);
        setError(null);
      } else {
        setAvailableTimeSlots([]);
        setError(`Doctor is not available on ${dayOfWeek}s`);
      }
    }
  }, [formData.appointmentDate, doctor]);

  const fetchDoctorDetails = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`http://localhost:5000/api/doctors/${doctorId}`);
      setDoctor(response.data);
      setError(null);
    } catch (err) {
      setError('Error fetching doctor details. Please try again.');
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.appointmentTime) {
      setError('Please select an appointment time');
      return;
    }

    try {
      setSubmitStatus({ loading: true, error: null });

      const appointmentData = {
        ...formData,
        doctor: doctorId,
        age: parseInt(formData.age, 10)
      };

      await axios.post('http://localhost:5000/api/appointments', appointmentData);

      navigate('/appointments');
    } catch (err) {
      setSubmitStatus({
        loading: false,
        error: err.response?.data?.message || 'Error creating appointment'
      });
    }
  };

  if (loading) {
    return (
      <div className="loading">
        <h2>Loading...</h2>
        <p>Please wait while we fetch the doctor's details.</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error">
        <h2>Error</h2>
        <p>{error}</p>
        <button onClick={fetchDoctorDetails} className="retry-btn">
          Try Again
        </button>
      </div>
    );
  }

  return (
    <div className="appointment-form">
      <h2>Book Appointment</h2>
      {doctor && (
        <div className="doctor-info">
          <h3>Doctor Details</h3>
          <p><strong>Name:</strong> Dr. {doctor.name}</p>
          <p><strong>Specialization:</strong> {doctor.specialization}</p>
          <p><strong>Consultation Fee:</strong> ${doctor.consultationFee}</p>
          <p><strong>Available Days:</strong> {doctor.availableDays.join(', ')}</p>
        </div>
      )}

      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label htmlFor="patientName">Full Name</label>
          <input
            type="text"
            id="patientName"
            name="patientName"
            value={formData.patientName}
            onChange={handleInputChange}
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="patientEmail">Email</label>
          <input
            type="email"
            id="patientEmail"
            name="patientEmail"
            value={formData.patientEmail}
            onChange={handleInputChange}
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="patientPhone">Phone Number</label>
          <input
            type="tel"
            id="patientPhone"
            name="patientPhone"
            value={formData.patientPhone}
            onChange={handleInputChange}
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="age">Age</label>
          <input
            type="number"
            id="age"
            name="age"
            min="0"
            max="150"
            value={formData.age}
            onChange={handleInputChange}
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="gender">Gender</label>
          <select
            id="gender"
            name="gender"
            value={formData.gender}
            onChange={handleInputChange}
            required
          >
            <option value="">Select Gender</option>
            <option value="Male">Male</option>
            <option value="Female">Female</option>
            <option value="Other">Other</option>
          </select>
        </div>

        <div className="form-group">
          <label htmlFor="appointmentDate">Preferred Date</label>
          <input
            type="date"
            id="appointmentDate"
            name="appointmentDate"
            value={formData.appointmentDate}
            onChange={handleInputChange}
            min={new Date().toISOString().split('T')[0]}
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="appointmentTime">Preferred Time</label>
          <select
            id="appointmentTime"
            name="appointmentTime"
            value={formData.appointmentTime}
            onChange={handleInputChange}
            required
          >
            <option value="">Select a time slot</option>
            {availableTimeSlots.map((slot, index) => (
              <option key={index} value={slot}>
                {slot}
              </option>
            ))}
          </select>
          {formData.appointmentDate && availableTimeSlots.length === 0 && (
            <p className="error-message">No time slots available for selected date</p>
          )}
        </div>

        <div className="form-group">
          <label htmlFor="symptoms">Symptoms</label>
          <textarea
            id="symptoms"
            name="symptoms"
            value={formData.symptoms}
            onChange={handleInputChange}
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="notes">Additional Notes (Optional)</label>
          <textarea
            id="notes"
            name="notes"
            value={formData.notes}
            onChange={handleInputChange}
          />
        </div>

        <button 
          type="submit" 
          className="submit-btn"
          disabled={submitStatus.loading}
        >
          {submitStatus.loading ? 'Booking...' : 'Book Appointment'}
        </button>

        {submitStatus.error && (
          <p className="error-message">{submitStatus.error}</p>
        )}
      </form>
    </div>
  );
};

export default AppointmentForm;
